question.answer:
#include "employee.h"

#include <stdio.h>
#include <stdlib.h>

Employee *new_employee_array(int n){
	Employee *new = malloc(n * sizeof(Employee));
	return new;
}

void delete_employee_array(Employee **arr) {
	free(*arr);
	*arr = NULL;
	}

void enter_details(Employee *emp){
	printf("Enter details of employee %d: ", emp->employee_number);
	scanf(" %s %s %s %f", 
	emp->first_name, emp->last_name, emp->job_title, &(emp->salary));
}

Employee *get_highest_paid(Employee employees[], int length){
	Employee *e = &employees[0];
	for(int i = 1; i < length; i++){
		if (e->salary < employees[i].salary){
			e = &employees[i];
		}
	}
	return e;
}

void print_details(Employee *emp){
	printf("----------------------------------\n");
	printf("Employee Record\n");
	printf("----------------------------------\n");
	printf("Employee number: %d\n", emp->employee_number);
	printf("Name:            %s, %s\n", emp->last_name, emp->first_name);
	printf("Job Title:       %s\n", emp->job_title);
	printf("Salary:          %.2f\n", emp->salary);
	printf("----------------------------------\n");
}
